    """Performs a single optimization step.
    Arguments:
        closure (callable, optional): A closure that reevaluates the model
            and returns the loss
    """
    loss = None
    if closure is not None:
        with torch.enable_grad():
            loss = closure()
    idx = 0
    for group in self.param_groups:
        for p in group["params"]:
            if p.grad is None:
                continue
            grad = p.grad + self.weight_decay * p
            if grad.is_sparse:
                raise RuntimeError(
                    "SFW does not yet support sparse gradients."
                )
            state = self.state[p]
            if len(state) == 0:
                state["step"] = 0
                state["grad_estimate"] = torch.zeros_like(
                    p, memory_format=torch.preserve_format
                )
                if self.track_active_set:
                    state["active_set"] = collections.defaultdict(float)
                    state["active_set"][p.detach().clone()] = 1.0

            if self.lr == "sublinear":
                step_size = 1.0 / (state["step"] + 1.0)
            elif type(self.lr) == float:
                step_size = self.lr
            else:
                raise ValueError("lr must be float or 'sublinear'.")

            if self.momentum is None:
                rho = (1.0 / (state["step"] + 1)) ** (1 / 3)
                momentum = 1.0 - rho
            else:
                momentum = self.momentum

            state["step"] += 1.0

            state["grad_estimate"].add_(
                grad - state["grad_estimate"], alpha=1.0 - momentum
            )
            update_direction, _ = self.lmo[idx](-state["grad_estimate"], p)
            state["certificate"] = (
                -state["grad_estimate"] * update_direction
            ).sum()
            if self.normalization == "gradient":
                grad_norm = torch.norm(state["grad_estimate"])
                step_size = min(
                    1.0,
                    step_size
                    * grad_norm
                    / torch.

