        return []

    self.lambda_ = lambda_

    assert 0 <= step_length_l1 <= 1, "Expected a real value in [0,1], but got {}".format(
        step_length_l1)
    model.eval()
    adv_x = x.detach()

    def one_iteration(_adv_x, norm_type):
        if "rnn" in model.model_save_path:
            model.train()
