            model, var_adv_x, label, self.lambda_)
        grads = torch.autograd.grad(
            loss.mean(), var_adv_x, allow_unused=True)
        if grads[0] is None:
            grad = torch.zeros_like(var_adv_x)
        else:
            grad = grads[0].data

